1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, [], 0)).toBe(5);
8	  });
9	
10	  // Base premiums per item type (newcomer, no modifiers beyond first insurance & fee)
11	  it("single plain sword for newcomer (no prior contracts) → base 100 + 10 first + 5 fee = 115 G", () => {
12	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 0)).toBe(115);
13	  });
14	  it("single plain amulet for newcomer → base 60 + 6 first + 5 fee = 71 G", () => {
15	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], 0)).toBe(71);
16	  });
17	  it("single plain staff for newcomer → base 80 + 8 first + 5 fee = 93 G", () => {
18	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }], 0)).toBe(93);
19	  });
20	  it("single plain potion for newcomer → base 40 + 4 first + 5 fee = 49 G", () => {
21	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }], 0)).toBe(49);
22	  });
23	
24	  // Components — base premiums (newcomer; verifying base before block rule)
25	  it("2 runes → base 50 G (no block; +5 first +5 fee = 60 G)", () => {
26	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }], 0)).toBe(60);
27	  });
28	  it("3 runes → base 60 G via block (+6 first +5 fee = 71 G)", () => {
29	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }], 0)).toBe(71);
30	  });
31	  it("4 runes → base 100 G (no block; block requires exactly 3) → +10 first +5 fee = 115 G", () => {
32	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], 0)).toBe(115);
33	  });
34	  it("7 runes → base 175 G (+17.5 first → 192.5 + 5 fee = 198 rounded up)", () => {
35	    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
36	    expect(quote({ yearsWithMHPCO: 0 }, items, 0)).toBe(198);
37	  });
38	
39	  // "Alike" components clarification
40	  it("2 runes + 1 moonstone → base 75 G (no block — different types) → 88 G", () => {
41	    expect(
42	      quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], 0),
43	    ).toBe(88);
44	  });
45	  it("3 runes + 3 moonstones → base 120 G (two separate blocks) → 137 G", () => {
46	    const items = [
47	      { type: "rune" }, { type: "rune" }, { type: "rune" },
48	      { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
49	    ];
50	    expect(quote({ yearsWithMHPCO: 0 }, items, 0)).toBe(137);
51	  });
52	
53	  // Item-specific modifiers
54	  it("cursed sword for newcomer → 100 + 50 curse + 10 first + 5 fee = 165 G", () => {
55	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }], 0)).toBe(165);
56	  });
57	  it("sword with enchantment exactly 5 (newcomer) → 100 + 30 high-ench + 10 first + 5 fee = 145 G", () => {
58	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 5 }], 0)).toBe(145);
59	  });
60	  it("sword with enchantment 4 (newcomer) → no high-ench surcharge → 115 G", () => {
61	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", enchantment: 4 }], 0)).toBe(115);
62	  });
63	  it("cursed sword with enchantment 5 (newcomer) → both surcharges apply → 195 G", () => {
64	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true, enchantment: 5 }], 0)).toBe(195);
65	  });
66	
67	  // Modifier scope on multi-item policies (clarifying question ❓)
68	  it("policy: cursed sword + plain amulet → 231 G (210 + 16 first + 5 fee)", () => {
69	    expect(
70	      quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }, { type: "amulet" }], 0),
71	    ).toBe(231);
72	  });
73	
74	  // Loyalty discount threshold
75	  it("customer with exactly 2 years + sword → loyalty 20% off policy base → 95 G", () => {
76	    expect(quote({ yearsWithMHPCO: 2 }, [{ type: "sword" }], 0)).toBe(95);
77	  });
78	  it("customer with 1 year + sword → no loyalty discount → 115 G", () => {
79	    expect(quote({ yearsWithMHPCO: 1 }, [{ type: "sword" }], 0)).toBe(115);
