81	
82	  // Follow-up contract discount (each contract after the first → 15% off policy base)
83	  it("second contract (priorContracts=1) for newcomer + sword → 15% follow-up off policy base → 100 G", () => {
84	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 1)).toBe(100);
