86	
87	  // First insurance per item, regardless of customer history (❓ clarification)
88	  it("long-standing customer's second contract: cursed sword ench 7 → premium 160 G (spec integration example)", () => {
89	    expect(
90	      quote({ yearsWithMHPCO: 3 }, [{ type: "sword", cursed: true, enchantment: 7 }], 1),
91	    ).toBe(160);
92	  });
93	
94	  // Rounding in MHPCO's favor
95	  it("premium calculation yielding 197.5 → final premium 198 (rounded up) — covered by 7 runes test", () => {
96	    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
97	    expect(quote({ yearsWithMHPCO: 0 }, items, 0)).toBe(198);
98	  });
99	
100	  // Errors
101	  it("unknown item type in quote → throws error", () => {
102	    expect(() => quote({ yearsWithMHPCO: 0 }, [{ type: "broomstick" }], 0)).toThrow();
103	  });
104	});
105	
106	describe("MHPCO Claim Office — claim", () => {
107	  // Standard reimbursement (no special clauses)
108	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
109	  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");
110	
111	  // Enchantment ≥8 clause
112	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
113	
114	  // Dragon material clause
115	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");
116	
117	  // Both clauses — 50% wins, then deductible
118	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
119	  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
120	
121	  // Deductible per damage event
122	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
123	
124	  // Multiple items of same type
125	  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
126	  it.todo("damages array has more entries of a type than the policy covers → throws error");
127	
128	  // Cap exhaustion
129	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
130	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
131	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
132	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");
133	
134	  // Rounding for payouts
135	  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
136	
137	  // Errors
138	  it.todo("claim references damage for an item not in the policy → throws error");
139	  it.todo("claim contains damage with negative amount → throws error");
140	});
