1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  cursed?: boolean;
8	  enchantment?: number;
9	}
10	
11	export interface Damage {
12	  itemType: string;
13	  amount: number;
14	}
15	
16	export interface Incident {
17	  cause: string;
18	  damages: Damage[];
19	}
20	
21	export interface Policy {
22	  items: Item[];
23	  insuranceSum: number;
24	  cap: number;
25	  remainingCap: number;
26	}
27	
28	const PROCESSING_FEE = 5;
29	const FIRST_INSURANCE_RATE = 0.1;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	const BLOCK_BASE = 60;
42	
43	const baseForGroup = (type: string, count: number): number => {
44	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
45	  return BASE_PREMIUM[type] * count;
46	};
47	
48	const countByType = (items: Item[]): Map<string, number> => {
49	  const counts = new Map<string, number>();
50	  for (const item of items) {
51	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
52	  }
53	  return counts;
54	};
55	
56	const sum = (numbers: number[]): number =>
57	  numbers.reduce((total, n) => total + n, 0);
58	
59	const groupBaseTotal = (items: Item[]): number => {
60	  const counts = countByType(items);
61	  return sum(
62	    Array.from(counts, ([type, count]) => baseForGroup(type, count)),
63	  );
64	};
65	
66	const itemSurchargeTotal = (items: Item[]): number =>
67	  sum(items.map((item) => surchargesFor(item)));
68	
69	const surchargesFor = (item: Item): number => {
70	  const base = BASE_PREMIUM[item.type];
71	  let total = 0;
72	  if (item.cursed) total += base * 0.5;
73	  if ((item.enchantment ?? 0) >= 5) total += base * 0.3;
74	  return total;
75	};
76	
77	const LOYALTY_THRESHOLD_YEARS = 2;
78	const LOYALTY_DISCOUNT_RATE = 0.2;
79	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
80	
81	export const quote = (
82	  customer: Customer,
83	  items: Item[],
84	  priorContracts: number,
85	): number => {
86	  for (const item of items) {
87	    if (!(item.type in BASE_PREMIUM)) {
88	      throw new Error(`Unknown item type: ${item.type}`);
89	    }
90	  }
91	  const groupBase = groupBaseTotal(items);
92	  const firstInsurance = groupBase * FIRST_INSURANCE_RATE;
93	  const surcharges = itemSurchargeTotal(items);
94	  const loyaltyDiscount =
95	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? groupBase * LOYALTY_DISCOUNT_RATE : 0;
96	  const followUpDiscount = priorContracts > 0 ? groupBase * FOLLOW_UP_DISCOUNT_RATE : 0;
97	  return Math.ceil(
98	    groupBase + firstInsurance + surcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
99	  );
100	};
101	
102	export const claim = (
103	  _policy: Policy,
104	  _incident: Incident,
105	): { payout: number; remainingCap: number } => {
106	  return undefined as unknown as { payout: number; remainingCap: number };
107	};
